class Person {
  String name = '';
  int age = 0;
}

void main() {
  var p = Person(); // default constructor called
}

class Person {
  String name;
  int age;

  Person(this.name, this.age);
}

void main() {
  var p = Person('Alice', 30);
}

class Person {
  String name;
  int age;

  Person(this.name, this.age);

  Person.guest() {
    name = 'Guest';
    age = 18;
  }

  Person.fromJson(Map<String, dynamic> json)
      : name = json['name'],
        age = json['age'];
}

void main() {
  var p1 = Person('Bob', 25);
  var p2 = Person.guest();
  var p3 = Person.fromJson({'name': 'Charlie', 'age': 28});
}

class Point {
  int x, y;

  Point(this.x, this.y);

  // Redirects to the main constructor
  Point.origin() : this(0, 0);
}

void main() {
  var p = Point.origin(); // x=0, y=0
}

class ImmutablePoint {
  final int x, y;

  const ImmutablePoint(this.x, this.y);
}

void main() {
  var p1 = const ImmutablePoint(1, 2);
  var p2 = const ImmutablePoint(1, 2);
  print(identical(p1, p2)); // true (same instance)
}

class Logger {
  final String name;
  static final Map<String, Logger> _cache = {};

  factory Logger(String name) {
    return _cache.putIfAbsent(name, () => Logger._internal(name));
  }

  Logger._internal(this.name);
}

void main() {
  var log1 = Logger('UI');
  var log2 = Logger('UI');
  print(identical(log1, log2)); // true (same cached instance)
}

class Person {
  String name;
  int age;

  Person(String name, int age)
      : assert(age >= 0),
        name = name,
        age = age;
}

void main() {
  var p = Person('Alice', 30);
}

class Animal {
  String name;
  Animal(this.name);
}

class Dog extends Animal {
  String breed;

  Dog(String name, this.breed) : super(name);
}

void main() {
  var d = Dog('Rex', 'Labrador');
}

